"use client";
import {
  Search,
} from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card } from "@/components/ui/card";
import { useRouter } from "next/router";
import { useState } from "react";

export default function Home() {
  const [url, setUrl] = useState("");     // 入力されたURL
  const [error, setError] = useState(""); // エラーメッセージ
  const [isLoading, setIsLoading] = useState(false);
  const [selectedCommand, setSelectedCommand] = useState("page");

  const router = useRouter();

  const isValidUrl = (input: string) : boolean => {
    try {
      // URLの分析
      const parsed = new URL(input.startsWith("http") ? input : `https://${input}`);
      // 有効なURLかどうか判定
      return parsed.protocol === "http:" || parsed.protocol === "https:";
    } catch {
      return false;
    }
  };

  // 分析開始ボタンが押された時の処理
  const handleSubmit = async () => {
    // バリデーション
    if(!url.trim()) {
      setError("URLを入力してください");
      return;
    }
    if(!isValidUrl(url)) {
      setError("正しいURLを入力してください")
      return;
    }

    setError("");
    setIsLoading(true);

    try {
      // TODO: バックエンド実装後に実際のAPI呼び出しに置き換える

      // 今はダミーのIDで結果ページに遷移する
      const dummyID = btoa(`${selectedCommand}:${url}`).replace(/=/g,"");
      router.push(`/result/${dummyID}`);
    } catch {
      setError("分析の開始に失敗しました。もう一度お試しください。");
      setIsLoading(false);
    }
  }

  return (
    <div>
      {/* ヘッダー */}
      <div className="text-center space-y-2">
        <h1 className="text-6xl font-bold tracking-tight flex items-center justify-center gap-2">
          FileSearch SEO 分析
          <Search className="w-12 h-12" />
        </h1>
        <p>URLを入力して、分析の種類を選んでください</p>
      </div>

      <div className="space-y-8">
      <Input
            type="url"
            placeholder="https://example.com"
            value={url}
            onChange={(e) => {
              setUrl(e.target.value);
              setError(""); // 入力が変わったらエラーをクリア
            }}
            onKeyDown={(e) => {
              // Enterキーで分析開始
              if (e.key === "Enter") handleSubmit();
            }}
            className="h-12 text-base"
            aria-label="分析するサイトのURL"
          />
          {error && (
            <p className="text-sm text-destructive">{error}</p>
          )}
      </div>
    </div>
  );
}
